Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenRequestSucceeds()
    {
        // Arrange
        var handler = new MockHttpMessageHandler("expected content", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        string result = await fetcher.FetchAsync("https://example.com/data");

        // Assert
        Assert.AreEqual("expected content", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_WhenResponseIsNotSuccess()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com/data"));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceledException_WhenTokenIsCancelled()
    {
        var handler = new MockHttpMessageHandler("content", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com/data", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // fail-safe: test must complete within 5s
    public async Task FetchAsync_PassesCancellationToken_ToHttpClient()
    {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));
        var handler = new MockHttpMessageHandler("content", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com/data", cts.Token));
    }

    // Reusable fake handler
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| **Async tests** | Return `async Task` — MSTest awaits them natively |
| **Timeout** | `[Timeout(5000)]` fails the test if it hangs (ms) |
| **Cancellation** | Pre-cancelled token and timed `CancellationTokenSource` |
| **HttpClient testing** | Subclass `HttpMessageHandler` — no mocking library needed |
| **Exception assertions** | `Assert.ThrowsExceptionAsync<T>` for async throws |

> **MSTest v3+ note:** If you're on MSTest 3.x+, you can also use `[TestMethod(Timeout = 5000)]` directly on the attribute and `Assert.ThrowsExactlyAsync<T>` for stricter type matching (no derived types).
